function runTasks(graph, callback, limit = 2) {
  const taskPromises = {};
  const executionQueue = [];
  let activeTask = 0;

  function processQueue() {
    if (activeTask < limit && executionQueue.length !== 0) {
      let taskToExecute = executionQueue.shift();
      taskToExecute();
    }
  }
  function enqueueTask(task) {
    return new Promise((resolve) => {
      executionQueue.push(() => {
        activeTask++;
        task().then(() => {
          activeTask--;
          processQueue();
          resolve();
        });
      });
      processQueue();
    });
  }
  // Helper function to execute a task
  function executeTask(name) {
    if (taskPromises[name]) {
      return taskPromises[name];
    }
    const { dependency = [], task } = graph[name];
    // Wait for all dependencies to resolve before running the task
    const dependencies = dependency.map(executeTask);
    // Execute the task after all its dependencies
    taskPromises[name] = Promise.all(dependencies).then(() =>
      enqueueTask(task)
    );
    return taskPromises[name];
  }
  // Execute all tasks and wait for their completion
  const allTasks = Object.keys(graph).map(executeTask);
  // Once all tasks are done, call the callback
  Promise.all(allTasks).then(callback);
}
