Can be done like:

````
function runAsyncGraph(graph, callback) {
  const totalTasks = Object.keys(graph).length;
  let tasksDone = 0;

  const markComplete = (id) => {
    tasksDone++;

    Object.entries(graph).forEach(([taskId,val]) => {
      if(val.dependency && val.dependency.length>0){
      const idx = val.dependency.indexOf(id);
      if(idx > -1){
        val.dependency.splice(idx,1);
        if(val.dependency.length === 0){
              if(++tasksDone >= totalTasks){
                   return val.task(callback);
              }
              else{
              val.task(() => {
                markComplete(taskId);
              });
              }
        }
      }        
      }
    });
  };

  Object.entries(graph).forEach(([key,val]) => {
    if(!val.dependency){
      val.task(() => {
        markComplete(key);
      });
    }  
  });

}
