import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ArrayBlockingQueue;
import java.util.concurrent.BlockingQueue;
import java.util.concurrent.Callable;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;

public class JobExecution {

	private static final ExecutorService executorService = Executors.newCachedThreadPool();
	private static final Map<String, BlockingQueue<Future<Void>>> map = new ConcurrentHashMap<>();

	private static final Map<String, Callable<Void>> callableMap = new HashMap<>();
	private static final Map<String, String[]> dependenciesMap = new HashMap<>();

	// Dependencies should finish first before taskID.
	// Assume I have callables corresponding to all the tasks.
	// Multiple graphs could be possible.
	public void addTask(String taskId, Callable<Void> callable, String[] dependencies) {
		callableMap.put(taskId, callable);
		dependenciesMap.put(taskId, dependencies);
	}

	public void executeGraph() {
		for (String taskId : callableMap.keySet()) {
			map.put(taskId, new ArrayBlockingQueue<Future<Void>>(1));
		}
		for (String taskId : callableMap.keySet()) {
			Callable<Void> callable = callableMap.get(taskId);
			String[] dependencies = dependenciesMap.get(taskId);
			CustomRunnable customRunnable = new CustomRunnable(taskId, dependencies, callable);
			Future<Void> future = executorService.submit(customRunnable);
			map.get(taskId).add(future);
		}
	}

	public static Future<Void> getFuture(String taskId) {
		return map.get(taskId).peek();
	}

	static class CustomRunnable implements Callable<Void> {

		private final String taskId;
		private final String[] dependencies;
		private final Callable<Void> callable;

		public CustomRunnable(String taskId, String[] dependencies, Callable<Void> callable) {
			this.taskId = taskId;
			this.dependencies = dependencies;
			this.callable = callable;
		}

		@Override
		public Void call() throws Exception {
			// wait for dependencies to finish
			// it will pull all the future objects from Map
			for (String taskId : dependencies) {
				JobExecution.getFuture(taskId).get();
			}
			callable.call();
			return null;
		}
	}

	static class SampleCallable implements Callable<Void> {

		private String taskId;

		public SampleCallable(String taskId) {
			this.taskId = taskId;
		}

		@Override
		public Void call() throws Exception {

			System.out.println("Executing " + taskId);
			Thread.sleep(5000);
			return null;
		}
	}

	public static void main(String[] args) {
		JobExecution jobExecution = new JobExecution();
		jobExecution.addTask("4", new SampleCallable("4"), new String[] { "1", "2" , "5"});
		jobExecution.addTask("5", new SampleCallable("5"), new String[] { "2", "3" });
		jobExecution.addTask("6", new SampleCallable("6"), new String[] { "4", "5" });
		jobExecution.addTask("1", new SampleCallable("1"), new String[] {});
		jobExecution.addTask("2", new SampleCallable("2"), new String[] {});
		jobExecution.addTask("3", new SampleCallable("3"), new String[] {});
		jobExecution.executeGraph();
	}
}
